    /**
     * Forward: maps source objects to target types based on their role in the intermediate container.
     * Iterates over intermediate objects, creates target objects per role, and adds them to objectMap.
     */
    private static void mapRoleBasedTypes(
            Families.FamilyRegister sourceRoot,
            Persons.PersonRegister targetRoot,
            Map<EObject, EObject> objectMap) {
        // FamilyMember → role-based target types via Family
        for (Families.Family family : sourceRoot.getFamilies()) {
            if (family.getFather() != null) {
                Families.FamilyMember member = family.getFather();
                Persons.Male obj = PersonsFactory.eINSTANCE.createMale();
                obj.setName(family.getName() + ", " + member.getName());
                targetRoot.getPersons().add(obj);
                objectMap.put(member, obj);
            }
            if (family.getMother() != null) {
                Families.FamilyMember member = family.getMother();
                Persons.Female obj = PersonsFactory.eINSTANCE.createFemale();
                obj.setName(family.getName() + ", " + member.getName());
                targetRoot.getPersons().add(obj);
                objectMap.put(member, obj);
            }
            for (Families.FamilyMember member : family.getSons()) {
                Persons.Male obj = PersonsFactory.eINSTANCE.createMale();
                obj.setName(family.getName() + ", " + member.getName());
                targetRoot.getPersons().add(obj);
                objectMap.put(member, obj);
            }
            for (Families.FamilyMember member : family.getDaughters()) {
                Persons.Female obj = PersonsFactory.eINSTANCE.createFemale();
                obj.setName(family.getName() + ", " + member.getName());
                targetRoot.getPersons().add(obj);
                objectMap.put(member, obj);
            }
        }
    }

    /**
     * Backward: maps target objects back to source type, assigns to role in intermediate container.
     * Creates intermediate objects as needed and assigns members to roles based on options.
     */
    private static void mapRoleBasedTypesBack(
            Persons.PersonRegister targetRoot,
            Families.FamilyRegister sourceRoot,
            Options options) {
        // Person → FamilyMember via Family
        Map<String, Families.Family> familyLookup = new HashMap<>();
        for (Persons.Person targetObj : targetRoot.getPersons()) {
            String intermediateKey = targetObj.getName().contains(",") ? targetObj.getName().substring(0, targetObj.getName().indexOf(',')) : targetObj.getName();
            String memberName = targetObj.getName().contains(",") ? targetObj.getName().substring(targetObj.getName().indexOf(',') + 1) : "";
            Families.Family family =
                    options.preferExistingFamily() ? familyLookup.getOrDefault(intermediateKey, null) : null;
            if (family == null) {
                family = FamiliesFactory.eINSTANCE.createFamily();
                family.setName(intermediateKey);
                sourceRoot.getFamilies().add(family);
                familyLookup.put(intermediateKey, family);
            }
            Families.FamilyMember member = FamiliesFactory.eINSTANCE.createFamilyMember();
            member.setName(memberName.trim());
            if (targetObj instanceof Persons.Male) {
                if (options.preferParentOverChildRole() && family.getFather() == null) {
                    family.setFather(member);
                } else {
                    family.getSons().add(member);
                }
            } else if (targetObj instanceof Persons.Female) {
                if (options.preferParentOverChildRole() && family.getMother() == null) {
                    family.setMother(member);
                } else {
                    family.getDaughters().add(member);
                }
            }
        }
    }

