    /**
     * Transforms FamilyMember → Person
     */
    private static Persons.Person transformFamilyMember(Families.FamilyMember source, Options options) {
        if (source == null) {
            return null;
        }
        
        Persons.Person target = null;
		// Role-based type mapping via Family
        if (source.eContainer() instanceof Families.Family) {
			Families.Family family = (Families.Family) source.eContainer();
			if (family.getFather() == source || family.getSons().contains(source)) {
				target = PersonsFactory.eINSTANCE.createMale();
			} else if (family.getMother() == source || family.getDaughters().contains(source)) {
				target = PersonsFactory.eINSTANCE.createFemale();
			} 
		} 

        target.setName(((Family)source.eContainer()).getName() + ", " + source.getName());
        return target;
    }

    /**
     * Transforms Person → FamilyMember (backward)
     */
    private static Families.FamilyMember transformBackPerson(Persons.Person target, Options options) {
        if (target == null) {
            return null;
        }

        Families.FamilyMember source = FamiliesFactory.eINSTANCE.createFamilyMember();

        //source.setName(target.getName().contains(", ") ? target.getName().substring(0, target.getName().indexOf(", ")) : target.getName());
        source.setName(target.getName().contains(", ") ? target.getName().substring(target.getName().indexOf(", ") + 1) : "");
        source.setName(source.getName().trim());
        return source;
    }

